query:
CREATE CONSTRAINT onet_occ_soc_code IF NOT EXISTS
FOR (o:OnetOccupation)
REQUIRE o.soc_code IS UNIQUE;

CREATE CONSTRAINT esco_occ_uri IF NOT EXISTS
FOR (e:EscoOccupation)
REQUIRE e.esco_occ_uri IS UNIQUE;

CREATE CONSTRAINT esco_skill_uri IF NOT EXISTS
FOR (s:EscoSkill)
REQUIRE s.esco_skill_uri IS UNIQUE;

CREATE CONSTRAINT skill_category_uri IF NOT EXISTS
FOR (c:SkillCategory)
REQUIRE c.category_uri IS UNIQUE;

LOAD CSV WITH HEADERS FROM 'file:///onet_occupations_tech_clean.csv' AS row
MERGE (o:OnetOccupation {soc_code: row.soc_code})
SET o.title = row.title;

MATCH (o:OnetOccupation)-[:CROSSWALK_TO]->(e:EscoOccupation)-[:REQUIRES_ESCO_SKILL]->(s:EscoSkill)
RETURN o.title, e.label, s.label
LIMIT 25;

MATCH (c:SkillCategory)
RETURN c.level, count(*) AS count
ORDER BY c.level;

CREATE CONSTRAINT custom_role_id IF NOT EXISTS
FOR (r:CustomRole)
REQUIRE r.role_id IS UNIQUE;

CREATE CONSTRAINT role_family_name IF NOT EXISTS
FOR (f:RoleFamily)
REQUIRE f.name IS UNIQUE;

CREATE CONSTRAINT esco_skill_uri IF NOT EXISTS
FOR (s:EscoSkill)
REQUIRE s.esco_skill_uri IS UNIQUE;

CREATE CONSTRAINT course_url IF NOT EXISTS
FOR (c:Course)
REQUIRE c.url IS UNIQUE;

CREATE CONSTRAINT cert_url IF NOT EXISTS
FOR (c:Certification)
REQUIRE c.url IS UNIQUE;

CREATE CONSTRAINT custom_role_id IF NOT EXISTS
FOR (r:CustomRole)
REQUIRE r.role_id IS UNIQUE;
